const Pool = pg.Pool;

function requiredEnv(name) {
    const value = env.get(name);
    if (!value) {
        throw new Error("Missing required environment variable: " + name);
    }
    return value;
}

function getPool() {
    let pool = flow.get("pgPool");
    if (pool) {
        return pool;
    }
    pool = new Pool({
        host: env.get("POSTGRES_HOST") || "postgres",
        port: Number(env.get("POSTGRES_PORT") || 5432),
        database: requiredEnv("POSTGRES_DB"),
        user: requiredEnv("POSTGRES_USER"),
        password: requiredEnv("POSTGRES_PASSWORD"),
        max: 10,
        idleTimeoutMillis: 30000,
        connectionTimeoutMillis: 5000
    });
    flow.set("pgPool", pool);
    return pool;
}

async function query(text, values) {
    const params = values || [];
    if (!Array.isArray(params)) {
        throw new Error("Database query values must be an array.");
    }
    return getPool().query(text, params);
}

function telegramRequest(methodName, payload) {
    return {
        method: "POST",
        url: "https://api.telegram.org/bot" + requiredEnv("TELEGRAM_BOT_TOKEN") + "/" + methodName,
        headers: { "Content-Type": "application/json" },
        payload
    };
}

function sendMessage(chatId, text, replyMarkup) {
    const payload = {
        chat_id: chatId,
        text,
        parse_mode: "HTML",
        disable_web_page_preview: true
    };
    if (replyMarkup) {
        payload.reply_markup = replyMarkup;
    }
    return telegramRequest("sendMessage", payload);
}

function answerCallbackQuery(callbackQueryId, text) {
    const payload = { callback_query_id: callbackQueryId };
    if (text) {
        payload.text = text;
    }
    return telegramRequest("answerCallbackQuery", payload);
}

function escapeHtml(value) {
    return String(value ?? "")
        .replace(/&/g, "&amp;")
        .replace(/</g, "&lt;")
        .replace(/>/g, "&gt;")
        .replace(/\"/g, "&quot;");
}

function chunkText(text, maxLength) {
    const limit = maxLength || 3800;
    if (text.length <= limit) {
        return [text];
    }
    const chunks = [];
    let current = "";
    for (const line of text.split("\n")) {
        if ((current + "\n" + line).length > limit) {
            if (current) chunks.push(current);
            current = line;
        } else {
            current = current ? current + "\n" + line : line;
        }
    }
    if (current) chunks.push(current);
    return chunks;
}

function formatDate(isoDate) {
    const parts = isoDate.split("-");
    return parts[2] + "." + parts[1] + "." + parts[0];
}

function formatName(name) {
    if (!name) return "";
    return String(name).trim().split(/\s+/).map(function(word) {
        return word ? word.charAt(0).toUpperCase() + word.slice(1).toLowerCase() : "";
    }).join(" ");
}

function contactLine(contact) {
    const username = contact.telegram_username ? ", " + escapeHtml(contact.telegram_username) : "";
    return escapeHtml(formatName(contact.first_name)) + " " + escapeHtml(formatName(contact.last_name)) + " — " + formatDate(contact.birth_date) + username;
}

