function isLeapYear(year) {
    return (year % 4 === 0 && year % 100 !== 0) || year % 400 === 0;
}

function dateFromParts(year, month, day) {
    const safeMonth = month === 2 && day === 29 && !isLeapYear(year) ? 3 : month;
    const safeDay = month === 2 && day === 29 && !isLeapYear(year) ? 1 : day;
    return new Date(Date.UTC(year, safeMonth - 1, safeDay));
}

function daysUntilNextBirthday(isoDate, fromDate) {
    const parts = isoDate.split("-").map(Number);
    const birthYear = parts[0];
    const month = parts[1];
    const day = parts[2];
    const baseDate = fromDate || new Date();
    const today = new Date(Date.UTC(baseDate.getUTCFullYear(), baseDate.getUTCMonth(), baseDate.getUTCDate()));
    let next = dateFromParts(today.getUTCFullYear(), month, day);
    if (next < today) next = dateFromParts(today.getUTCFullYear() + 1, month, day);
    return { days: Math.round((next - today) / 86400000), age: next.getUTCFullYear() - birthYear, date: next.toISOString().slice(0, 10) };
}

