function normalizeBirthdayDate(year, month, day) {
    if (month === 2 && day === 29 && !isLeapYear(year)) return { year, month: 3, day: 1 };
    return { year, month, day };
}

function toIsoDate(year, month, day) {
    return String(year).padStart(4, "0") + "-" + String(month).padStart(2, "0") + "-" + String(day).padStart(2, "0");
}

function localParts(timezone, now) {
    const formatter = new Intl.DateTimeFormat("en-CA", { timeZone: timezone, year: "numeric", month: "2-digit", day: "2-digit", hour: "2-digit", minute: "2-digit", hour12: false, hourCycle: "h23" });
    const parts = Object.fromEntries(formatter.formatToParts(now || new Date()).map(function(part) { return [part.type, part.value]; }));
    return { year: Number(parts.year), month: Number(parts.month), day: Number(parts.day), hour: parts.hour, minute: parts.minute };
}

function addDays(year, month, day, days) {
    const date = new Date(Date.UTC(year, month - 1, day + Number(days)));
    return { year: date.getUTCFullYear(), month: date.getUTCMonth() + 1, day: date.getUTCDate() };
}

function birthdayMatchesTarget(birthDateIso, target) {
    const parts = birthDateIso.split("-").map(Number);
    const normalized = normalizeBirthdayDate(target.year, parts[1], parts[2]);
    return normalized.month === target.month && normalized.day === target.day;
}

function reminderText(row, birthdayDate, daysBefore) {
    const name = escapeHtml(row.first_name) + " " + escapeHtml(row.last_name);
    const username = row.telegram_username ? "\nTelegram: " + escapeHtml(row.telegram_username) : "";
    const age = birthdayDate.year - Number(row.birth_date.split("-")[0]);
    const lead = daysBefore === 0 ? "Сьогодні день народження у " + name + "." : "Через " + daysBefore + " дн. день народження у " + name + ".";
    return ["<b>Нагадування</b>", "", lead, "Дата: " + String(birthdayDate.day).padStart(2, "0") + "." + String(birthdayDate.month).padStart(2, "0") + "." + birthdayDate.year, "Виповнюється: " + age + " років", username].filter(Boolean).join("\n");
}

